const r = $input.first().json.report || {};
const t = r.totals || {};
const byAgent = r.by_agent || [];
const byProject = r.by_project_30d || [];
const byModel = r.by_model_30d || [];
const errs = r.recent_errors || [];
const card = (label, value, unit, color) => '<div style="background:'+(color||'#f9fafb')+';padding:14px;border-radius:8px;flex:1;min-width:140px"><div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:.5px">'+label+'</div><div style="font-size:24px;font-weight:bold;color:#1f2937;margin-top:6px">'+(value!=null?value:'-')+(unit?'<span style="font-size:13px;color:#6b7280;font-weight:normal"> '+unit+'</span>':'')+'</div></div>';
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:8px;border-bottom:1px solid #e5e7eb;font-size:13px">'+c+'</td>').join('')+'</tr>';
const fmt = (n) => Number(n||0).toLocaleString('es-ES', {maximumFractionDigits: 4});
const agentRows = byAgent.length>0 ? byAgent.map(a=>row([
  '<b>'+a.agent_name+'</b>',
  String(a.calls_total),
  '<span style="color:'+(a.calls_error>0?'#dc2626':'#10b981')+'">'+a.calls_error+'</span>',
  fmt(a.cost_usd_total)+' USD',
  fmt(a.cost_usd_avg)+' USD',
  String(a.latency_ms_avg)+' ms',
  String(a.tokens_in_total + a.tokens_out_total)
])).join('') : row(['<i>Sin datos en 30d</i>','','','','','','']);
const projectRows = byProject.length>0 ? byProject.map(p=>row([
  '<b>'+p.project_name+'</b>',
  String(p.calls),
  fmt(p.cost_usd_total)+' USD'
])).join('') : row(['<i>Sin datos en 30d</i>','','']);
const modelRows = byModel.length>0 ? byModel.map(m=>row([
  '<code>'+m.model+'</code>', String(m.calls), fmt(m.cost_usd_total)+' USD'
])).join('') : row(['<i>Sin datos en 30d</i>','','']);
const errRows = errs.length>0 ? errs.map(e=>row([
  new Date(e.occurred_at).toISOString().slice(0,16).replace('T',' '),
  e.agent_name, e.model, '<code>'+e.status+'</code>', e.error_preview||'-'
])).join('') : row(['<i style="color:#10b981">Sin errores en 7d</i>','','','','']);
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ArquitAI LLM Costs</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 8px}h2{color:#374151;font-size:16px;margin:24px 0 8px}.cards{display:flex;gap:12px;flex-wrap:wrap;margin:16px 0}table{width:100%;border-collapse:collapse;background:white;border-radius:8px;overflow:hidden}thead{background:#1f2937;color:white}thead th{padding:10px 8px;text-align:left;font-size:12px}.meta{color:#64748b;font-size:13px}</style>' +
'</head><body>' +
'<h1>ArquitAI LLM Costs <a href="javascript:location.reload()" style="background:#2563eb;color:white;padding:4px 12px;border-radius:4px;text-decoration:none;font-size:13px;margin-left:8px">Refrescar</a></h1>' +
'<div class="meta">Snapshot ' + new Date().toLocaleString('es-ES') + '</div>' +
'<h2>Coste agregado</h2>' +
'<div class="cards">' +
  card('Coste 24h', fmt(t.last_24h_usd), 'USD') +
  card('Coste 7d', fmt(t.last_7d_usd), 'USD') +
  card('Coste 30d', fmt(t.last_30d_usd), 'USD') +
  card('Calls 24h', t.calls_24h||0) +
  card('Errores 24h', t.errors_24h||0, null, (t.errors_24h||0)>0?'#fee2e2':null) +
  card('Latencia avg', t.avg_latency_24h||0, 'ms') +
'</div>' +
'<h2>Por agente (30d)</h2>' +
'<table><thead><tr><th>Agente</th><th>Calls</th><th>Errors</th><th>Coste total</th><th>Coste avg</th><th>Latencia avg</th><th>Tokens</th></tr></thead><tbody>'+agentRows+'</tbody></table>' +
'<h2>Por proyecto (30d, top 15)</h2>' +
'<table><thead><tr><th>Proyecto</th><th>Calls</th><th>Coste</th></tr></thead><tbody>'+projectRows+'</tbody></table>' +
'<h2>Por modelo (30d)</h2>' +
'<table><thead><tr><th>Modelo</th><th>Calls</th><th>Coste</th></tr></thead><tbody>'+modelRows+'</tbody></table>' +
'<h2>Errores recientes (7d)</h2>' +
'<table><thead><tr><th>Cuando</th><th>Agente</th><th>Modelo</th><th>Status</th><th>Error</th></tr></thead><tbody>'+errRows+'</tbody></table>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">Datos de la tabla llm_calls (migration 035). Vista llm_costs_summary disponible en BD.</p>' +
'</body></html>';
return [{ json: { html: html } }];
